import React from 'react';

export default function Sidebar() {
  return (
    <nav className="sidebar bg-primary text-white p-3 d-flex flex-column">
      <h3 className="mb-3">College Tracker</h3>
      <ul className="nav flex-column">
        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Dashboard</a></li>
        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Assignments</a></li>
        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Calendar</a></li>
        <li className="nav-item mb-2"><a className="nav-link text-white" href="#">Export</a></li>
      </ul>
      <div className="mt-auto small">© College</div>
    </nav>
  );
}
